import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);

  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: true, // 편집 허용
        resultType: CameraResultType.Uri, // 결과는 Uri로 받기
        source: CameraSource.Camera, // 카메라 바로 실행
        saveToGallery: true, // 촬영 후 갤러리에 저장
      });

      console.log("사진 촬영 성공:", image);
      setPhoto(image.webPath); // 미리보기 경로 설정
    } catch (err) {
      console.error("카메라 오류:", err);
      // alert(JSON.stringify(err)); // 필요 시 주석 해제하여 에러 확인
    }
  };

  return (
    // 1. 전체 컨테이너: 배경색과 패딩, 반응형 너비
    <div style={containerStyle}>
      <div style={appCardStyle}>
        {/* 2. 헤더 영역: 로고 아이콘과 제목 */}
        <div style={headerStyle}>
          <span style={logoIconStyle}>📸</span>
          <h1 style={titleStyle}>My Camera App</h1>
          <p style={subtitleStyle}>토이 프로젝트 - 사진 촬영 테스트</p>
        </div>

        {/* 3. 사진 미리보기 영역: 테두리와 그림자 */}
        <div style={previewContainerStyle}>
          {photo ? (
            <img src={photo} alt="촬영된 사진" style={photoStyle} />
          ) : (
            <div style={noPhotoStyle}>
              <span style={{ fontSize: "50px" }}>📷</span>
              <p style={{ marginTop: "10px", color: "#888" }}>
                아직 촬영된 사진이 없습니다.
              </p>
            </div>
          )}
        </div>

        {/* 4. 액션 버튼 영역 */}
        <div style={actionStyle}>
          <button onClick={takePhoto} style={buttonStyle}>
            {photo ? "다시 찍기" : "사진 찍기"}
          </button>
        </div>
      </div>

      {/* 5. 푸터 영역 */}
      <footer style={footerStyle}>
        <p>Created by Hyeon. Using React, Capacitor, and JS.</p>
      </footer>
    </div>
  );
}

// --- 인라인 스타일 정의 ---

const containerStyle = {
  backgroundColor: "#f0f2f5", // 연한 회색 배경
  minHeight: "100vh",
  padding: "20px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  fontFamily: "'Noto Sans KR', sans-serif",
};

const appCardStyle = {
  backgroundColor: "#fff",
  width: "100%",
  maxWidth: "400px", // 모바일 카드 너비
  borderRadius: "20px",
  boxShadow: "0 10px 25px rgba(0,0,0,0.05)", // 부드러운 그림자
  padding: "30px",
  marginTop: "30px",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};

const headerStyle = {
  textAlign: "center",
  marginBottom: "30px",
};

const logoIconStyle = {
  fontSize: "40px",
};

const titleStyle = {
  fontSize: "24px",
  fontWeight: "bold",
  margin: "10px 0 5px 0",
  color: "#333",
};

const subtitleStyle = {
  fontSize: "14px",
  color: "#777",
  margin: 0,
};

const previewContainerStyle = {
  width: "100%",
  height: "300px",
  backgroundColor: "#f9f9f9",
  borderRadius: "15px",
  border: "2px dashed #ddd", // 점선 테두리
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  overflow: "hidden", // 이미지가 영역을 벗어나지 않도록
  marginBottom: "30px",
};

const photoStyle = {
  width: "100%",
  height: "100%",
  objectFit: "cover", // 이미지를 비율에 맞춰 꽉 채우기
};

const noPhotoStyle = {
  textAlign: "center",
  color: "#bbb",
};

const actionStyle = {
  width: "100%",
};

const buttonStyle = {
  width: "100%",
  padding: "15px",
  fontSize: "18px",
  fontWeight: "bold",
  color: "#fff",
  backgroundColor: "#007aff", // 애플 스타일 블루
  border: "none",
  borderRadius: "10px",
  cursor: "pointer",
  transition: "background-color 0.2s", // 호버 효과용 (작동 안 함)
  boxShadow: "0 4px 10px rgba(0,122,255,0.3)",
};

const footerStyle = {
  marginTop: "auto", // 하단으로 밀어내기
  textAlign: "center",
  fontSize: "12px",
  color: "#aaa",
  paddingTop: "40px",
};

export default App;
